// src/Dashboard.js
import React from "react";
import { useNavigate } from "react-router-dom";

const green = "#0f9d58";
const lightGreen = "#eaf8f0";
const white = "#ffffff";

export default function Dashboard({ employee }) {
  const navigate = useNavigate();

  return (
    <div
      style={{
        fontFamily: "Segoe UI",
        background: lightGreen,
        minHeight: "100vh",
        padding: 20,
      }}
    >
      <div
        style={{
          maxWidth: 900,
          margin: "0 auto",
          background: white,
          borderRadius: 14,
          boxShadow: "0 6px 20px rgba(0,0,0,0.12)",
          overflow: "hidden",
        }}
      >
        {/* Header with Back Arrow */}
        <header
          style={{
            padding: 16,
            background: green,
            color: white,
            display: "flex",
            alignItems: "center",
            gap: 12,
          }}
        >
          <button
            onClick={() => navigate("/profile")}
            style={{
              background: "transparent",
              border: "none",
              color: white,
              fontSize: 24,
              cursor: "pointer",
            }}
          >
            ←
          </button>

          <div style={{ fontSize: 18, fontWeight: 700 }}>
            Employee Dashboard
          </div>
        </header>

        {/* Employee Information Only */}
        <main style={{ padding: 18 }}>
          <h3 style={{ color: green, marginBottom: 8 }}>Employee Information</h3>

          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fit, minmax(220px,1fr))",
              gap: 12,
              background: "#f9fff9",
              borderRadius: 10,
              padding: 16,
              border: `1px solid ${lightGreen}`,
            }}
          >
            <Info label="Name" value={employee.name} />
            <Info label="Employee ID" value={employee.empld} />
            <Info label="Department" value={employee.department} />
            <Info label="Role" value={employee.role} />
            <Info label="Email" value={employee.email} />
            <Info label="Phone" value={employee.phone} />
            <Info label="Joining Date" value={employee.joiningDate} />
          </div>
        </main>
      </div>
    </div>
  );
}

function Info({ label, value }) {
  return (
    <div style={{ fontSize: 14 }}>
      <span style={{ fontWeight: 600, color: "#2e7d32" }}>{label}:</span>{" "}
      <span>{value}</span>
    </div>
  );
}
